 assessment.getCreatedAt(),
 assessment.getUpdatedAt()
 );
 }

 private QuestionResponse convertToQuestionResponse(Question question) {
 return new QuestionResponse(
 question.getId(),
 question.getText(),
 question.getOptionIds().stream()
 .map(this::convertToOptionResponse).collect(Collectors.toList()),
 question.getCorrectOptionId(),
 question.getTags()
 );
 }

 private OptionResponse convertToOptionResponse(Option option) {
 return new OptionResponse(option.getId(), option.getText());
 }

 private Question getQuestionById(String id) {
 return questionRepo.findById(id)
 .orElseThrow(() -> new RuntimeException("Question not found with ID: " + id));
 }

}
